import React from 'react';
import {slugify} from "../../../utils";
import PropTypes from "prop-types";
import {Link} from "react-router-dom";
import useLangPath from "../../../hooks/useLangPath";

const BlogListTwo = ({ data, StyleVar }) => {
    const langPath = useLangPath();
    // const cate = data.categories.map((value, i) => {
    //     return (
    //         <Link to={process.env.PUBLIC_URL + `/blog/category/${slugify(value)}`} key={i}>{value}{i !== data.categories.length - 1 && ","}</Link>
    //     )
    // });
    
    return (
        <div 
            className={`rn-card ${StyleVar}`}
            style={{
                border:'1px solid lightgray'
            }}
        >
            <Link to={langPath('/blog', { id: data.id })} className="inner">
                <div className="thumbnail">
                    <div 
                        className="image"
                        style={{
                            height:'100%'
                        }}
                    >
                        <img 
                            src={`${process.env.PUBLIC_URL}/${data.image}`} 
                            alt="Blog Image" 
                            style={{
                                height:'100%',
                                objectFit:'cover'
                            }}
                        />
                    </div>
                </div>
                <div className="content">
                    <h4 className="title">
                        {data.title}
                    </h4>
                    <ul className="rn-meta-list">
                        {/* <li><Link to={process.env.PUBLIC_URL + `/archive/${slugify(data.author)}`}>{data.author}</Link></li> */}
                        {/* <li className="separator">/</li> */}
                        <li>{data.date}</li>
                    </ul>
                    <p className="descriptiion">{data.excerpt}</p>
                </div>
            </Link>
        </div>
    )
}
BlogListTwo.propTypes = {
    data: PropTypes.object
};
export default BlogListTwo;
